import {Device, types} from 'mediasoup-client';
import * as protoo from 'protoo-client';
import { Stream } from "./Stream";
import { AbstractRoom } from './AbstractRoom';

/**
 * 本地媒体流
 * - 由RTC视频房间对象{@link ClientRoom}创建；外部不能直接new构造
 * - 可对本地媒体流进行初始化、发布、取消发布、暂停、恢复、替换媒体流（如切换摄像头）、关闭
 */
export class LocalStream extends Stream {
  /** @internal */
  _transport?: types.Transport;
  /** @internal */
  _protoo?: protoo.Peer;
  /** @internal */
  _producer: {audio?:types.Producer, video?:types.Producer} = {};
  /** @internal */
  _videoCodecPayloadType?:number;
   /** @internal */
  _room:AbstractRoom


  /**
   * 构造
   * - 只应该由ClientRoom来构造，否则将无法正常发布到RTC音视频房间
   * @param id 媒体流ID
   * @param appData 媒体流关联的用户数据
   * @internal
   */
  constructor(id: string, appData: any, room:AbstractRoom) {
    super(id, true, appData);
    this._room = room;
  }
  /**
   * 是否已经发布
   * - {@link publish}成功，published将更新为true
   * - {@link unpublish}成功，published将更新为false
   * @category Main
   */
  get published(): boolean { return (this._producer.audio || this._producer.video)?true:false; }

  /**
   * 初始化本地媒体流
   * - 为了音频视频同步，一般同时初始化音频视频，而不是单独创建音频、视频的LocalStream对象
   * @category Main
   * @param isWebcam 视轨类型。true-表示摄像头；false-表示共享桌面
   * @param constraints 媒体约束。见WebRTC MediaStreamConstraints定义
   */
  init = (isWebcam: boolean, constraints: MediaStreamConstraints) => {
    const self = this;
    return new Promise<void>(async (resolve, reject) => {
      if(constraints.audio && !self._room.__device.canProduce('audio')) { // 房间不允许有音轨
        reject('forbid to publish audio at this room');
        return;
      }
      if(constraints.video && !self._room.__device.canProduce('video')) {// 房间不允许有视轨
        reject('forbid to publish video at this room');
        return;
      }
      if(self._audioTrack || self._videoTrack) { // 已初始化过了
        reject('stream have inited');
        return;
      }
      try {
        let stream:MediaStream;
        if(isWebcam) {
          stream = await navigator.mediaDevices.getUserMedia(constraints);
        } else {
          stream = await (navigator.mediaDevices as any).getDisplayMedia(constraints)
        }
        if(stream.getAudioTracks().length>0) self._audioTrack = stream.getAudioTracks()[0];
        if(stream.getVideoTracks().length>0) self._videoTrack = stream.getVideoTracks()[0];

        if(!self._transport) self._transport = await self._room.__createStreamTransport('produce', self.onWebRtcStateChanged);

        resolve();
        console.info(`local stream(${self._id}) inited`);
      } catch(reason) {
        reject(reason);
      }
    });
  }

  /**
   * 发布媒体流
   * - 发布成功，则房间中其他参与者将接收到【参与者发布媒体流事件{@link evt_peer_published}】
   * @category Main
   */
  publish = () => {
    const self = this;
    return new Promise<void>(async (resolve, reject) => {
      if(!self._audioTrack && !self._videoTrack) { // 未初始化
        reject('need to initialize');
        return;
      }
      if(self._producer.audio || self._producer.video) { // 已发布
        reject('already published');
        return;
      }
      if(self._videoTrack && !self._room.__device.canProduce('video')) { // 房间是不允许发布视轨
        reject('forbid to publish video at this room');
        return;
      }
      if(self._audioTrack && !self._room.__device.canProduce('audio')) { // 房间是不允许发布音轨
        reject('forbid to publish audio at this room');
        return;
      }
      const appData = { // 将流ID设置给生产者，如果媒体流既有音轨又有视轨，则接收端通过streamId、trackCount来合成RemoteStream
        streamId: self._id,
        trackCount: (self._audioTrack && self._videoTrack)?2:1,
        appData: self._appData,
      };
      try {
        if(self._videoTrack) {
          await self._publish_track(self._videoTrack, {...appData, video:true});
          console.info(`local stream(${self._id}) video track published`);
        }
        if(self._audioTrack) {
          await self._publish_track(self._audioTrack, {...appData, audio:true});
          console.info(`local stream(${self._id}) audio track published`);
        }
        resolve();
        console.info(`local stream(${self._id}) published`);
      } catch (reason) {
        self.unpublish();
        reject(reason);
      }
    });
  }

  /**
   * 取消发布
   * - 取消成功，则房间其他参与者对应{@link RemoteStream}将接收到【】
   * @category Main
   */
  unpublish = () => {
    console.info(`LocalStream.unpublish: call`);
    if(this._producer.audio) {
      this._producer.audio.close();
      this._producer.audio = undefined;
    }
    if(this._producer.video) {
      this._producer.video.close();
      this._producer.video = undefined;
    }
    console.info(`LocalStream.unpublish: finish`);
  }

  /**
   * 替换webrtc媒体流
   * @category Main
   * @param stream 新的webrtc媒体流
   */
  replace = (stream: MediaStream) => {
    const self = this;
    return new Promise<void>(async (resolve, reject) => {
      if(!self.published) {
        reject('stream have not published');
        return;
      }
      const video = stream.getVideoTracks().length>0?stream.getVideoTracks()[0]:undefined;
      const audio = stream.getAudioTracks().length>0?stream.getAudioTracks()[0]:undefined;
      if(video && !self._producer.video) {
        reject('stream video track have not pubished');
        return;
      }
      if(audio && !self._producer.audio) {
        reject('stream audio track have not pubished');
        return;
      }
      if(!video && !audio) {
        reject('stream no track');
        return;
      }
      try {
        if(video) {
          await self._producer.video?.replaceTrack({track:video});
          console.info(`local stream(${self._id}) video track replaced`);
        }
        if(audio) {
          await self._producer.audio?.replaceTrack({track:audio});
          console.info(`local stream(${self._id}) audio track replaced`);
        }
        resolve();
        console.info(`local stream(${self._id}) replaced`);
      } catch(reason) {
        reject(reason);
      }
    });
  }

  /**
   * 暂停发布（静音）
   * @param options
   * - options.audio==true，表示对音轨静音
   * - options.video==true，表示对视轨静音
   * - options==undefined或options=={audio:true,video:true}，表示同时对音轨、视轨静音
   * @category Main
   */
  pause = (options?: {audio?:boolean, video?: boolean}) => {
    if(this._producer.audio && !this._producer.audio.paused && (!options || options.audio)) 
      this._producer.audio.pause();
    if(this._producer.video && !this._producer.video.paused && (!options || options.video)) 
      this._producer.video.pause();
  }

  /**
   * 恢复发布（取消静音）
   * @param options
   * - options.audio==true，表示对音轨取消静音
   * - options.video==true，表示对视轨取消静音
   * - options==undefined或options=={audio:true,video:true}，表示同时对音轨、视轨取消静音
   * @category Main
   */
  resume = (options?: {audio?:boolean, video?: boolean}) => {
    if(this._producer.audio && this._producer.audio.paused && (!options || options.audio)) 
      this._producer.audio.resume();
    if(this._producer.video && this._producer.video.paused && (!options || options.video)) 
      this._producer.video.resume();
  }

  /**
   * 更新应用自定义数据
   * @category Main
   * @param appData 用户数据
   * @internal
   */
  updateAppData = (appData: any) => {
    const self = this;
    this._appData = appData;
    return new Promise<void>((resolve, reject) => {
      if(!self.published) {
        reject('stream have not published');
        return;
      }
      // 应用自定义数据只更新到一个生产者中
      let producerId = '';
      if(self._producer.video) producerId = self._producer.video.id;
      else if(self._producer.audio) producerId = self._producer.audio.id;

      self._protoo?.request('updateStreamUserData', {producerId, appData})
      .then(() => resolve())
      .catch(reason => reject(reason));
    });
  }

  /**
   * 关闭流
   * @category Main
   */
  close = () => {
    if(this._transport) {
      this._transport.close();
      this._transport = undefined;
    }
    this.stop();
    this._videoElem = undefined;
    this._fireCloseEvent();
  }

  /**
   * 单独发布音频、视频
   * @internal
   */
  private _publish_track = (track: MediaStreamTrack, appData: any) => {
    const self = this;
    return new Promise<void>( async (resolve, reject) => {
      // codecPayloadType 选择编码（默认由webrt自己选择）
      // maxBitrate 限制比特率
      // 
      const encodings = (track.kind==='video')?[{codecPayloadType:self._videoCodecPayloadType, maxBitrate: 614400}]:undefined
      self._transport?.produce({track, appData, encodings})
      .then( producer => {
        if(track.kind==='audio') self._producer.audio = producer;
        else self._producer.video = producer;
        resolve();
        console.info(`local stream(${self._id}) ${track.kind}Track(produerId=${producer.id}) published`);
      })
      .catch(reason => {
        reject(reason);
      });
    });
  }
}