import {Peer, WebSocketTransport, ProtooNotification, ProtooRequest, ProtooResponse} from 'protoo-client';
import {Device, types} from 'mediasoup-client';
import {LocalStream} from './LocalStream';
import {RemoteStream} from './RemoteStream';
import { AbstractRoom } from './AbstractRoom';

/**
 * RTC音视频房间
 */
export class ClientRoom implements AbstractRoom {

  /**
   * 回调函数，参与者进入房间
   * @category Callbacks
   */
  onPeerJoined?: (peerId: string, appData: any) => void;
  /**
   * 回调函数，参与者离开房间
   * @category Callbacks
   */
  onPeerLeaved?: (peerId: string) => void;
  /**
   * 回调函数，参与者发布音视频流房间
   * @category Callbacks
   */
  onPeerPublished?: (peerId: string, stream: RemoteStream) => void;
  /**
   * 回调函数，参与者网络连接丢失
   * @category Callbacks
   */
  onPeerLoss?: (peerId: string) => void;
  /**
   * 回调函数，参与者更新自身信息。
   * @category Callbacks
   */
  onPeerAppDataUpdated?: (peerId: string, appData: any) => void;
  /**
   * 回调函数，网络连接丢失
   * @category Callbacks
   */
  onNetLoss?: () => void;
  /**
   * 回调函数，网络重试
   * @category Callbacks
   */
  onNetRetrying?: (currentAttempt: number) => void;
  /**
   * 回调函数，网络故障已不可恢复
   * @category Callbacks
   */
  onNetFault?: () => void;
  /**
   * 回调函数，房间已关闭
   * @category Callbacks
   */
  onRoomClosed?: () => void;

  /**
   * 接收到文本消息
   */
  onTextMessage?: (peerId: string, text: string) => void;

  /** @internal */
  private _nextStreamId = Math.round(Math.random()*1000);
  /** @internal */
  private _peerId = '';
  /** @internal */
  __protoo?:Peer;
  /** @internal */
  private _maxRetry = 10;
  /** @internal */
  private _joined = false;
  /** @internal */
  __device:Device;
  /** @internal */
  private _appData: any;
  /** @internal */
  private _localStreams = new Map<string, LocalStream>();
  /** @internal */
  private _remoteStreams = new Map<string, RemoteStream>();
  /** @internal */
  private _pingTimer?: any;

  /** @internal */
  constructor() {
    this.__device = new Device();
  }

  /**
   * 房间自定义数据。通过视频服务管理API创建房间时设置；具体数据内容，由业务需求设置，可以设置房间标题等信息
   */
  get appData(): any {
    return JSON.parse(JSON.stringify(this._appData));
  }
  /**
   * 是否允许收发音轨
   * @internal
   */
  get audioAllowed(): boolean {
    if(this._joined) {
      return this.__device.canProduce('audio');
    }
    return false;
  }
  /**
   * 是否允许收发视轨
   * @internal
   */
  get videoAllowed(): boolean {
    if(this._joined) {
      return this.__device.canProduce('video');
    }
    return false;
  }
  /**
   * 关闭房间
   * @category Main
   */
  close = () => {
    this.cleanup();
    this.__stop_ping();
  }

  /** 
   * 进入房间<br>
   * - 视频服务提供了创建房间、创建参与者（并生成签名信息）管理接口，这些管理接口应该由相应业务服务（如ACD排队服务）来调用然后将生成的房间ID、参与者ID、签名信息传给本SDK。<br>
   * - 成功进入房间，房间中的其他参与者将接收到【参与者进入房间事件({@link evt_peer_joined})】。
   * @category Main
   * @param url webscoket服务器地址。必须以wss://开关（WebRTC只允许安全链接）
   * @param roomId 房间ID
   * @param peerId 参与者ID
   * @param sig 签名信息
   * @param appData 参与者自定义数据。视频服务将此数据转发给房间的其他参与者
   * @returns 
   * - appData 房间自定义数据
   * - peers 房间参与者列表
   * - peers[x].id 参与者ID
   * - peers[x].appData 参与者自定义数据
   *
  */
  join = (url: string, roomId: string, peerId: string, sig: string, appData: any) => {
    const self = this;
    // id及签名编译到url的Search Params中
    const wsUrl = new URL(url);
    wsUrl.searchParams.set('roomId', roomId);
    wsUrl.searchParams.set('peerId', peerId);
    wsUrl.searchParams.set('sig', sig);
    return new Promise<{peers: {id: string, appData: any}[], appData: any}>((resolve, reject) => {
      if(self._joined) {
        reject('already joined');
        return;
      }
      // 创建websocket连接
      self.__protoo = new Peer(new WebSocketTransport(wsUrl.toString()));
      self.__setup_protoo_event_handler(reject);
      self.__protoo.on('open', async () => {
        self.__join_internal(peerId, appData)
        .then( (peers) => {
          resolve(peers);
          self.__start_ping();
        })
        .catch( reason => reject(reason));
      });
    });
  }

  /** @internal */
  __open_websocket = (url: string) => {
    const self = this;
    return new Promise<void>((resolve, reject) => {
      if(self.__protoo) {
        self.__protoo.close();
        self.__protoo = undefined;
      }
      // 创建websocket连接
      self.__protoo = new Peer(new WebSocketTransport(url, {retry:{retries: 0}}));
      self.__setup_protoo_event_handler(reject);
      self.__protoo.on('open', async () => {
        resolve();
      });
    });
  }

  /**@internal */
  __setup_protoo_event_handler = (reject?: (reason: any) => void) => {
    if(!this.__protoo) 
      return;
      const self = this;
      this.__protoo.on('disconnected', () => {
      if(!self._joined && reject) { // 进入房间标记未设置，则表示一开始就连接失败，需要调用回调函数通知上层
        reject('connect failed');
      } else {
        //self.cleanup(); // 房间已失效，清理
        if(self.onNetLoss) self.onNetLoss();
      }
    });
    this.__protoo.on('close', () => {
      if(self.onRoomClosed) self.onRoomClosed();
    });
    this.__protoo.on('failed', (currentAttempt: number) => {
      if(currentAttempt<10) {
        if(self.onNetRetrying) self.onNetRetrying(currentAttempt);
      } else {
        if(self.onNetFault) self.onNetFault();
      }
    });
    this.__protoo.on('notification', (notif: ProtooNotification) => {
      switch(notif.method) {
        case 'room.closing': self.handleRoomClosing(); break;
        case 'peer.joined': self.handlePeerJoined(notif.data); break;
        case 'peer.leaved': self.handlePeerLeaved(notif.data); break;
        case 'peer.loss': self.handlePeerLoss(notif.data); break;
        case 'peer.appDataUpdated': self.handlePeerAppDataUpdated(notif.data); break;
        case 'peer.produced': self.handlePeerProduced(notif.data); break;
        case 'producer.score': self.handleProducerScore(notif.data); break;
        case 'consumer.transportclosed': self.handleConsumerTransportClosed(notif.data); break;
        case 'consumer.producerclosed': self.handleProducerClosed(notif.data); break;
        case 'consumer.producerpaused': self.handleProducerPaused(notif.data); break;
        case 'consumer.producerresumed': self.handleProducerResumed(notif.data); break;
        case 'consumer.score': self.handleConsumerScore(notif.data); break;
        case 'consumer.layerschanged': self.handleConsumerLayerChanged(notif.data); break;
        case 'textMessage': if(self.onTextMessage) self.onTextMessage(notif.data.peerId, notif.data.message); break;
        default: {
          if(self.__on_notification) self.__on_notification(notif.method, notif.data);
        }
      }
    });
    this.__protoo.on('request', ( request: ProtooRequest, 
      accept: (data?: ProtooResponse) => void, reject: (error?: Error | number, errorReason?: string) => void) => {
      if(self.__on_request) self.__on_request(request, accept, reject);
    });
  }

  /** @internal */
  __join_internal = (peerId: string, appData: any) => {
    const self = this;
    return new Promise<{peers: {id: string, appData: any}[], appData: any}>(async (resolve, reject) => {
      if(self._joined) {
        reject('already joined');
        return;
      }
      try {
        const response = await self.__protoo!.request('join', {appData});
        console.info('received join response');
        /*
        * data.rtpCapabilities 房间RTP能力{@link types.RtpCapabilities}。后续创建媒体流时需要用到
        * data.roomAppData 房间信息，由应用定义
        * data.peers 房间当前参与者列表
        */
        const {rtpCapabilities, roomAppData, peers} = response;

        self._peerId = peerId; // 保存peerId
        self._appData = roomAppData;
        self._joined = true; // 设置已经进入房间标记

        if(self.__device.loaded) {
          self.__device = new Device();
        }

        await self.__device.load({routerRtpCapabilities:rtpCapabilities}); // 加载RTP能力

        const joinedPeers:{id:string, appData: any}[] = [];
        peers.forEach( (joinedPeer:any) => {
          if(joinedPeer.producers) {
            joinedPeer.producers.forEach( (producer:any) => {
              let stream = self._remoteStreams.get(producer.appData.streamId);
              if(!stream) {
                stream = new RemoteStream(producer.appData.streamId, producer.appData.appData, self);
                stream._peerId = joinedPeer.id;
                self._remoteStreams.set(producer.appData.streamId, stream);
              }
              if(producer.appData.audio) stream._producer.audio = producer.id;
              if(producer.appData.video) stream._producer.video = producer.id;
              if((producer.appData.trackCount===2 && stream._producer.audio && stream._producer.video) ||
                (producer.appData.trackCount===1 && (stream._producer.audio || stream._producer.video))) {
                stream._completed = true;
              }
            });
          }
          joinedPeers.push({id:joinedPeer.id, appData: joinedPeer.appData});
        });
        resolve({appData: roomAppData, peers: joinedPeers});
        
        // 延迟500毫秒发送媒体流发布事件
        if( self._remoteStreams.size>0) {
          setTimeout(()=> {
            self._remoteStreams.forEach( stream => {
              if(stream._completed) {
                console.info(`peer(${stream.peerId}) publish stream(${stream.id})`);
                if(self.onPeerPublished) self.onPeerPublished(stream.peerId, stream);
              }
            });
          }, 500);
        }
        console.info('joined');
      } catch(reason) {
        reject(reason);
      }
    });
  }



  /** 
   * 离开房间
   * - 房间中的其他参与者将接收到【参与者离开房间事件({@link evt_peer_leaved})】
   * @category Main
   */
  leave = () => {
    console.info('ClientRoom.leave: call');
    const self = this;
    return new Promise<void>((resolve, reject) => {
      if(self._joined) {
        self.__protoo!.request('leave')
        .then(() => {
          self.cleanup();
          self._joined = false;
          console.info('ClientRoom.leave: finish');
          resolve();
        })
        .catch( reason => {
          console.error(`ClientRoom.leave: exception - ${JSON.stringify(reason)}`);
          reject(reason);
        });
      } else {
        console.info('ClientRoom.leave: finish, do nothing');
        resolve();
      }
    });
  }

  /**
   * 创建本地视频流
   * @category Main
   * @param appData 
   * @returns 
   */
  createLocalStream = (appData: any) => {
    if(!this._joined) {
      return undefined;
    }

    this._nextStreamId++;
    // 参与者ID（_peerId）+ 流ID（_peerId）才是唯一的
    const streamId = `${this._peerId}#${this._nextStreamId}`;
    const stream = new LocalStream(streamId, appData, this);
    this._localStreams.set(streamId, stream);
    return stream;
  }

  /**
   * 发送文本消息
   * @category Main
   * @param message 消息体
   * @returns 
   */
   sendText = (message: string) => {
    return this.__protoo?.notify('textMessage', {message});
  }

  /** @internal */
  private handleRoomClosing = () => {
    if(this.onRoomClosed) this.onRoomClosed();
  }
  /** @internal */
  private handlePeerJoined = (data: any) => {
    const {peerId, appData} = data;
    // 浏览器刷新，会重新加入房间，这时要清理旧的媒体流
    this._remoteStreams.forEach(stream => {
      if(stream.peerId===peerId) {
        console.info(`peer${peerId} joined: clean old stream(${stream.id})`)
        stream.close();
      }
    });
    if(this.onPeerJoined) this.onPeerJoined(peerId, appData);
  }
  /** @internal */
  private handlePeerLeaved = (data: any) => {
    const {peerId} = data;
    if(this.onPeerLeaved) this.onPeerLeaved(peerId);
    let keys: string[] = [];
    this._remoteStreams.forEach( stream => {
      if(peerId===stream.peerId) { // 只关闭这个离开的参与者的媒体流
        keys.push(stream._id);
        stream.close();
      }
    });
    keys.forEach( key => this._remoteStreams.delete(key));
  }
  /** @internal */
  private handlePeerLoss = (data:any) => {
    const {peerId} = data;
    if(this.onPeerLoss) this.onPeerLoss(peerId);
  }
  /** @internal */
  private handlePeerAppDataUpdated = (data: any) => {
    const {peerId, appData} = data;
    if(this.onPeerAppDataUpdated) this.onPeerAppDataUpdated(peerId, appData);
  }
  /** @internal */
  private handlePeerProduced = (data: any) => {
    const {peerId, producerId, paused,  appData} = data;
    //const {streamId, trackCount, appData, audio, video} = peerAppData;
    let stream = this._remoteStreams.get(appData.streamId);
    if (stream && stream._completed) {
      stream.close();
      stream = undefined;
    }
    if(!stream) {
      stream = new RemoteStream(appData.streamId, appData.appData, this);
      stream._peerId = peerId;
      this._remoteStreams.set(appData.streamId, stream);
    }
    if(appData.audio) stream._producer.audio = producerId;
    if(appData.video) stream._producer.video = producerId;
    if((appData.trackCount===2 && stream._producer.audio && stream._producer.video) ||
      (appData.trackCount===1 && (stream._producer.audio || stream._producer.video))) {
      stream._completed = true;
      console.info(`got completed stream: peer(${stream.peerId}), id(${appData.streamId}), producers(${JSON.stringify(stream._producer)})`);
      if(this.onPeerPublished) this.onPeerPublished(stream.peerId, stream);
    }
  }
  /** @internal */
  private handleProducerScore = (data: any) => {
    const {streamId, producerId, score} = data;

  }
  /** @internal */
  private handleProducerClosed = (data: any) => {
    const {streamId, consumerId} = data;
    const stream = this._remoteStreams.get(streamId);
    if(stream) {
      this._remoteStreams.delete(streamId);
      const fireEvent = stream.subscribed;
      stream.unsubscribe();
      stream.close();
    }
    
  }
  /** @internal */
  private handleProducerPaused = (data: any) => {
    const {streamId, consumerId} = data;
    const stream = this._remoteStreams.get(streamId);
    if(stream) stream._setRemotePaused(consumerId, true);
  }
  /** @internal */
  private handleProducerResumed = (data: any) => {
    const {streamId, consumerId} = data;
    const stream = this._remoteStreams.get(streamId);
    if(stream) stream._setRemotePaused(consumerId, false);
  }
  /** @internal */
  private handleConsumerScore = (data: any) => {
    const {streamId, consumerId, score} = data;
  }
  /** @internal */
  private handleConsumerTransportClosed = (data: any) => {
    const {streamId, consumerId} = data;
    const stream = this._remoteStreams.get(streamId);
    if(stream) {
      this._remoteStreams.delete(streamId);
      const fireEvent = stream.subscribed;
      stream.unsubscribe();
      stream.close();
    }
  }
  /** @internal */
  private handleConsumerLayerChanged = (data: any) => {
    const {streamId, consumerId, layers} = data;
    const {spatialLayer, temporalLayer} = layers;
  }
  /** @internal */
  private cleanup = () => {
    console.info(`ClientRoom.cleanup: call`);
    if(this._localStreams.size>0) {
      this._localStreams.forEach( stream => { 
        stream.unpublish();
        stream.close(); 
        console.info(`ClientRoom.cleanup: local stream(${stream.id}) cleanuped`);
      });
    }
    this._localStreams.clear();
    this._remoteStreams.forEach( stream => {
      stream.unsubscribe();
      stream.close();
      console.info(`ClientRoom.cleanup: remote stream(${stream.id}) cleanuped`);
    });
    this._remoteStreams.clear();
    console.info(`ClientRoom.cleanup: finish`);
  }

  /** @internal */
  __start_ping = () => {
    if(this._pingTimer)
      return;
    const self = this;
    // 定时ping
    setTimeout(() => {
      self._pingTimer = setInterval(() => {
        self.__protoo!.request('ping')
        .catch(reason => console.error(`ping error: ${JSON.stringify(reason)}`));
      }, 15000);
    }, 10000);
  }
  /** @internal */
  __stop_ping = () => {
    if(this._pingTimer) clearInterval(this._pingTimer);
    this._pingTimer = undefined;
  }

  /** @internal */
  __do_request = (method: string, data?: any) => {
    const self = this;
    return new Promise<any>((resolve, reject) => {
      if (self.__protoo) {
        self.__protoo.request(method, data)
        .then( value => resolve(value))
        .catch(reason => reject(reason));
      } else {
        reject('have not connected');
      }
    })
  }
  /** @internal */
  __do_notify = (method: string, data?: any) => {
    const self = this;
    return new Promise<any>((resolve, reject) => {
      if (self.__protoo) {
        self.__protoo.notify(method, data)
        .then( value => resolve(value))
        .catch(reason => reject(reason));
      } else {
        reject('have not connected');
      }
    })
  }
  /** @internal */
  __on_request?: (request: ProtooRequest, 
    accept: (data?: ProtooResponse) => void, reject: (error?: Error | number, errorReason?: string) => void) => void;
  /** @internal */
  __on_notification?: (method: string, data?: any) => void;

   /** @internal */
  __canProduce = (kind: types.MediaKind) => {
    return this.__device.canProduce(kind);
  }
   /** @internal */
  __rtpCapabilities = () => {
    return this.__device.rtpCapabilities;
  }

  /** @internal */
  __createStreamTransport = (type: 'produce'|'consume', stateChanged?: (newState: string) => void) => {
    const self = this;
    return new Promise<types.Transport>(async (resolve, reject) => {
      // mediasoup特有流程。mediasoup不能使用STUN/TURN，因为其传输端口由服务器确定（ICE LITE？）
      try {
        let response = await self.__protoo?.request('createWebRtcTransport') 
        const transport = type==='produce' ? self.__device.createSendTransport(response) : self.__device.createRecvTransport(response);
        transport.on('connect', ({ dtlsParameters }, callback, errback) => { // 本地已连接，则通知服务器端传输端口进行连接
          self.__protoo?.request('connectWebRtcTransport', { transportId: transport?.id, dtlsParameters})
          .then(callback)
          .catch(errback);
        });
      
        if(type==='produce') {
          transport.on('produce', ({kind, rtpParameters, appData}, callback, errback) => {
            self.__protoo?.request('produce', {transportId: transport?.id, kind, rtpParameters, appData})
            .then(data => { 
              console.info(`local stream request produce, new producerId=${data.producerId}`);
              callback({ id: data.producerId }); 
            })
            .catch(errback);
          });
        }
        
        transport.on('connectionstatechange', (state) => {
          console.info(`${type==='produce'?'local stream':'remote stream'} connectionstatechange state=${state}`);
          if(stateChanged) stateChanged(state);
          switch (state) {
            case 'failed':
              transport.close();
            break;
            default: break;
          }
        });

        resolve(transport);
      } catch(reason) {
        reject(reason);
      }
    });
  }

}