/**
 * 音视频流基类
 */
export class Stream {

  /**
   * 回调函数，媒体流传输状态发生变化
   * - "new"  ICE 代理正在搜集地址或者等待远程候选可用
   * - "checking": ICE 代理已收到至少一个远程候选，并进行校验，无论此时是否有可用连接。同时可能在继续收集候选
   * - "connected": ICE代理至少对每个候选发现了一个可用的连接，此时仍然会继续测试远程候选以便发现更优的连接。同时可能在继续收集候选
   * - "completed": ICE代理已经发现了可用的连接，不再测试远程候选
   * - "failed": ICE候选测试了所有远程候选没有发现匹配的候选。也可能有些候选中发现了一些可用连接
   * - "disconnected": 测试不再活跃，这可能是一个暂时的状态，可以自我恢复
   * - "closed": ICE代理关闭，不再应答任何请求
   * @category Callbacks
   */
  onWebRtcStateChanged?: (newState: string) => void;
  /**
   * 回调函数，媒体流已关闭
   * @category Callbacks
   */
  onClosed?: () => void;

  /** @internal */
  _id: string; // 流ID
  /** @internal */
  _local: boolean; // 是否本地流
  /** @internal */
  _paused: boolean; // 是否已经暂停
  /** @internal */
  _appData: any; // 流的自定义数据
  /** @internal */
  _videoElem?: HTMLVideoElement;
  /** @internal */
  _closed = false;
  /** @internal */
  _audioTrack?: MediaStreamTrack;
  /** @internal */
  _videoTrack?: MediaStreamTrack;
  /** @internal */
  _elemId = '';

  /**
   * 构造媒体流
   * @param id 媒体流ID
   * @param local 是否本地媒体流
   * @param appData 媒体流关联的自定义数据
   * @internal
   */
  constructor(id: string, local: boolean, appData: any) {
    this._id = id;
    this._paused = false;
    this._local = local;
    this._appData = JSON.parse(JSON.stringify(appData)); // 克隆
  }

  /**
   * 媒体流ID
   * - 同一参与者的不同媒体流，其ID是唯一的；不同参与者间的媒体流ID并不唯一
   * @category Main
   */
  get id(): string { return this._id; }
  /**
   * 是否本地媒体流
   * @category Main
   */
  get isLocal(): boolean { return this._local; }
  /**
   * 音轨
   * - 在{@link play}不能满足播放要求（如需要特效处理、css样式不合理）情况下，上层可以获取音轨，自行播放
   * @category Main
   */
  get audioTrack(): MediaStreamTrack|undefined { return this._audioTrack; }
  /**
   * 视轨
   * - 在{@link play}不能满足播放要求（如需要特效处理、css样式不合理）情况下，上层可以获取视轨，自行播放
   * @category Main
   */
  get videoTrack(): MediaStreamTrack|undefined { return this._videoTrack; }
  /**
   * 是否已暂停（暂停接收或暂停发布）
   * @category Main
   */
  get paused(): boolean { return this._paused;}
  /**
   * 媒体流自定义数据
   * - 对于{@link LocalStream}，此数据是调用{@link ClientRoom}的{@link createLocalStream}方法创建本地音视频流时设置的
   * - 调用{@link LocalStream}的{@link publish}，房间其他参与者产生对应的{@link RemoteStream}，RemoteStream.appData与对应的LocalStream.appData相同
   * @category Main
   */
  get appData(): any { 
    return JSON.parse(JSON.stringify(this._appData));
  }

  /**
   * 播放媒体流
   * - LocalStream只播放视轨（如果为共享桌面，则不应该调用此方法）
   * - RemoteStream播放音轨、视轨
   * @category Main
   * @param elemId 播放器(video标签)的父标签ID
   */
  play = (elemId: string) => {
    this._elemId = elemId;
    const elem = document.getElementById(elemId);
    if(elem && (this._audioTrack || this._videoTrack)) {
      this._videoElem = document.createElement('video');
      const stream = new MediaStream();
      if(!this._local && this._audioTrack)  // 本地流不用播放音轨
        stream.addTrack(this._audioTrack);
      if(this._videoTrack) 
        stream.addTrack(this._videoTrack);
      
      this._videoElem.srcObject = stream;
      this._videoElem.setAttribute("style", "height: 100%; width: 100%; object-fit: contain;");
      this._videoElem.controls = false;
      this._videoElem.autoplay = true;
      (this._videoElem as any).playsInline = true;
      
      elem.appendChild(this._videoElem);
      console.info(`play ${this._local?'local':'remote'} stream(${this._id}), succeeded`);
      return true;
    }
    console.error(`play ${this._local?'local':'remote'} stream(${this._id}), no track`);
    this._elemId = '';
    return false;
  }

  /**
   * 停止播放
   * @category Main
   */
  stop = () => {
    if(this._videoElem) {
      this._videoElem.srcObject = null;
      if(this._videoElem.parentNode) {
        this._videoElem.parentNode.removeChild(this._videoElem);
      }
    }
  }

  /**
   * 拍照
   * @category Main
   * @param mime 照片格式
   * @param ouput 输出数据格式。'blob'-表示回调函数返回的图片Blob数据；'base64'-表示回调函数返回的是base64编码的图片
   * @param cb 回调函数
   */
  snapshot = (mime: 'image/jpeg'|'image/png', ouput: 'blob'|'base64', cb: (image: string|Blob|null) => void) => {
    if(this._videoElem) {
      mime = mime || 'image/png';
      const canvas = document.createElement('canvas');
      canvas.width = this._videoElem.videoWidth;
      canvas.height = this._videoElem.videoHeight;
      const context = canvas.getContext('2d');
      if(context) {
        context.drawImage(this._videoElem, 0, 0, canvas.width, canvas.height);
        if(ouput==='blob') {
          canvas.toBlob(b => cb(b), mime);
        } else {
          cb(canvas.toDataURL(mime));
        }
      } else {
        cb(null);
      }
    } else {
      cb(null);
    }
  }

  /** @internal */
  _fireCloseEvent = () => {
    if(!this._closed) {
      this._closed = true;
      console.info(`stream(${this._id}) closed`);
      if(this.onClosed) this.onClosed();
    }
  }
}