import {Device, types} from 'mediasoup-client';
import * as protoo from 'protoo-client';
import { Stream } from "./Stream";
import { AbstractRoom } from './AbstractRoom';

/**
 * 远端媒体流
 * - 由RTC视频房间对象{@link ClientRoom}创建；外部不能直接new构造
 * - 可对远端媒体流进行订阅、取消订阅、暂停、恢复、关闭
 */
export class RemoteStream extends Stream {
  /**
   * 回调函数，媒体流暂停发布
   * @category Callbacks
   */
  onPaused?: () => void;
  /**
   * 回调函数，媒体流恢复发布
   * @category Callbacks
   */
  onResumed?: () => void;
  /**
   * 回调函数，参与者进入房间
   * @category Callbacks
   */
  onAppDataUpdated?: (appData: any) => void;

  /** @internal */
  _remotePaused = false;
  /** @internal */
  _room: AbstractRoom;
  /** @internal */
  _transport?: types.Transport;
  /** @internal */
  _producer: {audio?:string, video?:string} = {};
  /** @internal */
  _consumer: {audio?:types.Consumer, video?:types.Consumer} = {};
  /** @internal */
  _completed = false;
  /** @internal */
  _peerId = '';

  /** @internal */
  constructor(id: string, appData: any, room:AbstractRoom) {
    super(id, false, appData);
    this._room = room;
  }
  /** 
   * 音视频流关联的参与者ID 
   * @category Main
  */
  get peerId() {return this._peerId;}
  /** 
   * 音视频流是否包含音轨 
   * @category Main
   */
  get hasAudio() {return this._producer.audio?true:false;}
  /** 
   * 音视频流是否包含视轨 
   * @category Main
   */
  get hasVideo() {return this._producer.video?true:false;}
  /** 
   * 是否已订阅 
   * @category Main
   */
  get subscribed() { return (this._consumer.audio || this._consumer.video)?true:false; }
  /** 远端是否暂停发布 */
  get remotePaused() { return this._remotePaused; }

  /**
   * 暂停接收媒体流
   * @param options
   * - options.audio==true，表示对音轨静音
   * - options.video==true，表示对视轨静音
   * - options==undefined或options=={audio:true,video:true}，表示同时对音轨、视轨静音
   * @category Main
   */
  pause = (options?: {audio?:boolean, video?: boolean}) => {
    if(this._consumer.audio && !this._consumer.audio.paused && (!options || options.audio)) 
      this._consumer.audio.pause();
    if(this._consumer.video && !this._consumer.video.paused && (!options || options.video)) 
      this._consumer.video.pause();
  }

  /**
   * 恢复接收媒体流
   * - options.audio==true，表示对音轨取消静音
   * - options.video==true，表示对视轨取消静音
   * - options==undefined或options=={audio:true,video:true}，表示同时对音轨、视轨取消静音
   * @category Main
   */
  resume = (options?: {audio?:boolean, video?: boolean}) => {
    if(this._consumer.audio && !this._consumer.audio.paused && (!options || options.audio)) 
      this._consumer.audio.resume();
    if(this._consumer.video && !this._consumer.video.paused && (!options || options.video)) 
      this._consumer.video.resume();
  }

  /**
   * 订阅媒体流
   * @category Main
   */
  subscribe = () => {
    const self = this;
    return new Promise<void>(async (resolve, reject) => {
      if(self._consumer.audio || self._consumer.video) {
        reject('have subscibed');
        return;
      }
      try {
        if(!self._transport) self._transport = await self._room.__createStreamTransport('consume', self.onWebRtcStateChanged);
        
        if(self._producer.video) {
          await self._subscribe_track(self._producer.video, false);
          console.info(`remote stream(${self._id}) video track subscribed`);
        }
        if(self._producer.audio) {
          await self._subscribe_track(self._producer.audio, true);
          console.info(`remote stream(${self._id}) audio track subscribed`);
        }
        resolve();
        console.info(`remote stream(${self._id}) subscribed`);
      } catch(reason) {
        reject(reason);
      }
    });
  }

  /**
   * 取消订阅
   * @category Main
   */
  unsubscribe = () => {
    if(this._consumer.audio) {
      this._consumer.audio.close();
      this._consumer.audio = undefined;
    }
    if(this._consumer.video) {
      this._consumer.video.close();
      this._consumer.video = undefined;
    }
  }

  /**
   * 关闭流
   * @category Main
   */
  close = () => {
    if(this._consumer.audio) {
      this._consumer.audio.close();
      this._consumer.audio = undefined;
    }
    if(this._consumer.video) {
      this._consumer.video.close();
      this._consumer.video = undefined;
    }
    this.stop();
    this._videoElem = undefined;
    this._fireCloseEvent();
  }


  // ****************** 内部方法，由ClientRoom调用 ******************
  /** @internal */
  _setRemotePaused = (consumerId: string, paused: boolean) => {
    if((this._consumer.audio && this._consumer.audio.id === consumerId) ||
        (this._consumer.video && this._consumer.video.id === consumerId)) {
      if(this._remotePaused!==paused) {
        this._remotePaused = paused;
        if(this.subscribed) { // 已经订阅才发事件
          if(paused && this.onPaused) this.onPaused(); 
          else if(!paused && this.onResumed) this.onResumed();
        }
      }
    } else {
      this._remotePaused = paused;
    }
  }
  /** @internal */
  _setAppData = (appData: any) => {
    this._appData = appData;
    if(this.subscribed && this.onAppDataUpdated) this.onAppDataUpdated(appData); // 已经订阅才发事件
  }
  // ************************************************************
  /** @internal */
  private _subscribe_track = (producerId: string, audio: boolean) => {
    const self = this;
    return new Promise<void>( async (resolve, reject) => {
      const { rtpCapabilities } = self._room.__device;
      try {
        // 发送音轨或视轨消费请求
        let data = await self._room.__protoo?.request('consume', { transportId: self._transport?.id,producerId, 
                                          rtpCapabilities, paused: self._paused, appData: {streamId: self._id}});
        const {consumerId, kind, rtpParameters, producerPaused} = data;
        // 创建消费者
        const consumer = await self._transport!.consume({id: consumerId, producerId, kind, rtpParameters});
        if(audio) {
          self._consumer.audio = consumer;
          self._audioTrack = consumer.track;
        } else {
          self._consumer.video = consumer;
          self._videoTrack = consumer.track;
        }
        consumer.on('transportclose', () => {self._fireCloseEvent();});
        consumer.observer.on('close', () => {self._fireCloseEvent();});
        self._remotePaused = producerPaused;
        resolve();
        console.info(`remote stream(${self._id}) ${kind}Track(producerId=${producerId}) consumed`);
      } catch(reason) {
        reject(reason);
      }
    });
  }
}