
/** WebRTC媒体约束生成器 
 * 
*/
export class StreamConstraintsBuilder {

  /** @internal */
  __constraints:MediaStreamConstraints = {};

  /**
   * 启用音频（指麦克风） 
   */
  enableAudio = () => {
    this.__constraints.audio = true;
    return this;
  }
  /**
   * 设置麦克风设备ID。系统有多个麦克风，并且不使用系统默认麦克风时需要指定设备ID
   * @param deviceId  
   */
  setAudioDeviceId = (deviceId: string) => {
    if(typeof this.__constraints.audio === 'boolean' || !this.__constraints.audio) {
      this.__constraints.audio = {deviceId};
    } else {
      this.__constraints.audio.deviceId = deviceId;
    }
    return this;
  }
  /**
   * 启用视频（摄像头或共享桌面）
   */
  enableVideo = () => {
    this.__constraints.video = true;
    return this;
  }
  /**
   * 设置摄像头设备ID。系统有多个摄像头时，需要指定摄像头设备ID，否则将会使用navigator.mediaDevices.enumerateDevices()返回的第一个摄像头
   * @param deviceId 
   * @returns 
   */
  setVideoDeviceId = (deviceId: string) => {
    if(typeof this.__constraints.video === 'boolean' || !this.__constraints.video) {
      this.__constraints.video = {deviceId};
    } else {
      this.__constraints.video.deviceId = deviceId;
    }
    return this;
  }
  /**
   * 设置视频帧率
   * @param rate 帧率
   */
  setVideoFrameRate = (rate: number) => {
    if(typeof this.__constraints.video === 'boolean' || !this.__constraints.video) {
      this.__constraints.video = {frameRate: rate};
    } else {
      this.__constraints.video.frameRate = rate;
    }
    return this;
  }
  /**
   * 设置视频分辨率
   * @param size 分辨率，'1080P': 1920x1080，'720P'：1280x720，'480P'：640x480，'360P'：480x360
   */
  setVideoSize = (size: '1080P'|'720P'|'480P'|'360P') => {
    if(typeof this.__constraints.video === 'boolean' || !this.__constraints.video) {
      switch(size) {
        case '1080P': this.__constraints.video = {width: 1920, height: 1080}; break;
        case '720P': this.__constraints.video = {width: 1280, height: 720}; break;
        case '480P': this.__constraints.video = {width: 640, height: 480}; break;
        case '360P': this.__constraints.video = {width: 480, height: 360}; break;
      }
    } else {
      switch(size) {
        case '1080P': this.__constraints.video = {...this.__constraints.video, width: 1920, height: 1080}; break;
        case '720P': this.__constraints.video = {...this.__constraints.video, width: 1280, height: 720}; break;
        case '480P': this.__constraints.video = {...this.__constraints.video, width: 640, height: 480}; break;
        case '360P': this.__constraints.video = {...this.__constraints.video, width: 480, height: 360}; break;
      }
    }
    return this;
  }

  /**
   * 生成WebRTC媒体约束 
   */
  build = () => {
    return this.__constraints;
  }
}

/**
 * 获取摄像头列表
 * 
 * @returns 
 */
 export const getCameras = () => {
  return new Promise<{id:string, label: string}[]>(async (resolve, reject) => {
    try {
      const medias = await navigator.mediaDevices.enumerateDevices();
      let cameras:{id:string, label: string}[] = [];
      medias.forEach(media => {
        if(media.kind === 'videoinput') cameras.push({id: media.deviceId, label: media.label});
      });
      resolve(cameras);
    } catch(reason) {
      reject(reason);
    }
  });
}

/**
 * 获取麦克风列表
 * @returns 
 */
export const getMicrophones = () => {
  return new Promise<{id:string, label: string}[]>(async (resolve, reject) => {
    try {
      const medias = await navigator.mediaDevices.enumerateDevices();
      let cameras:{id:string, label: string}[] = [];
      medias.forEach(media => {
        if(media.kind === 'audioinput') cameras.push({id: media.deviceId, label: media.label});
      });
      resolve(cameras);
    } catch(reason) {
      reject(reason);
    }
  });
}